UPDATE practice_session_question
SET user_answer_json = #{userAnswerJson},
    user_answer_label = #{userAnswerLabel},
    answer_label = #{answerLabel},
    submitted = #{submitted},
    correct = #{correct},
    version = version + 1
WHERE session_id = #{sessionId}
  AND question_id = #{questionId}
  AND version = #{version}
